// Parser HTML Indeed → JSON
const cheerio = require('cheerio');

const html = $input.item.json;
const $ = cheerio.load(html);

const jobs = [];

$('a.tapItem').each((i, el) => {
  const title = $(el).find('h2.jobTitle').text().trim();
  const company = $(el).find('.companyName').text().trim();
  const location = $(el).find('.companyLocation').text().trim();
  const description = $(el).find('.job-snippet').text().trim();
  const url = 'https://fr.indeed.com' + $(el).attr('href');

  if (title && company) {
    jobs.push({
      title,
      company,
      location,
      raw_description: description,
      url,
      source: 'Indeed',
      scraped_at: new Date().toISOString()
    });
  }
});

console.log('✅ [Parser] Jobs extraits:', jobs.length);

return jobs.map(j => ({ json: j }));

/**
 * JSON VALIDATOR & CLEANER
 * Adapté du workflow Telegram-TikTok pour JobNexAI
 */

const requiredFields = [
  'title',
  'company',
  'location',
  'skills',
  'experience_level',
  'remote_type'
];

const defaultJobStructure = {
  title: $('Function - Parser HTML → JSON').item.json.title,
  company: $('Function - Parser HTML → JSON').item.json.company,
  location: $('Function - Parser HTML → JSON').item.json.location,
  skills: [],
  experience_level: 'non_specifie',
  salary_estimate: null,
  remote_type: 'non_specifie',
  contract_type: 'non_specifie',
  technologies: [],
  description_enriched: $('Function - Parser HTML → JSON').item.json.raw_description,
  benefits: [],
  quality_score: 5,
  error: true,
  error_message: 'Enrichissement IA échoué - données minimales conservées'
};

function validateAndCleanJSON(aiResponse, requiredFields, defaultStructure) {
  try {
    let parsedResponse;
    let cleanResponse;

    if (typeof aiResponse === 'object' && aiResponse !== null) {
      parsedResponse = aiResponse;
      cleanResponse = JSON.stringify(aiResponse, null, 2);
    } 
    else if (typeof aiResponse === 'string') {
      cleanResponse = aiResponse
        .replace(/^```json\s*/i, '')
        .replace(/^```\s*/i, '')
        .replace(/\s*```$/i, '')
        .replace(/\\n/g, '')
        .replace(/\\"/g, '"')
        .replace(/\\'/g, "'")
        .trim();

      parsedResponse = JSON.parse(cleanResponse);
    } 
    else {
      throw new Error(`Type de réponse inattendu: ${typeof aiResponse}`);
    }

    const missingFields = requiredFields.filter(field => {
      return !parsedResponse.hasOwnProperty(field) || 
             parsedResponse[field] === null || 
             parsedResponse[field] === undefined;
    });

    if (missingFields.length > 0) {
      console.warn('⚠️ [Validation] Champs manquants:', missingFields.join(', '));
      throw new Error(`Champs manquants: ${missingFields.join(', ')}`);
    }

    if (!Array.isArray(parsedResponse.skills)) {
      throw new Error('Le champ "skills" doit être un tableau');
    }

    console.log('✅ [Validation] JSON validé avec succès');

    return {
      json: {
        ...parsedResponse,
        url: $('Function - Parser HTML → JSON').item.json.url,
        source: $('Function - Parser HTML → JSON').item.json.source,
        scraped_at: $('Function - Parser HTML → JSON').item.json.scraped_at,
        validated: true,
        enriched: true,
        validation_timestamp: new Date().toISOString()
      }
    };

  } catch (error) {
    console.error('❌ [Validation] Erreur:', error.message);
    console.error('Réponse brute:', aiResponse);

    return {
      json: {
        ...defaultStructure,
        url: $('Function - Parser HTML → JSON').item.json.url,
        source: $('Function - Parser HTML → JSON').item.json.source,
        scraped_at: $('Function - Parser HTML → JSON').item.json.scraped_at,
        validation_error: error.message,
        validation_timestamp: new Date().toISOString()
      }
    };
  }
}

const aiResponse = $input.item.json.ai_response;
const result = validateAndCleanJSON(aiResponse, requiredFields, defaultJobStructure);

return result;
